document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".screenshot-img").forEach(e=>{e.addEventListener("error",function(){const e=document.getElementById("screenshot-container"),d=document.getElementById("docs-card"),t=document.getElementById("docs-card-content"),n=document.getElementById("background");e&&e.classList.add("!hidden"),d&&d.classList.add("!row-span-1"),t&&t.classList.add("!flex-row"),n&&n.classList.add("!hidden")})})});